        "GET": {
            parameters: {}
            return: {
                "console"?: "applet" | "vv" | "html5" | "xtermjs";
                "release": string;
                "repoid": string;
                "version": string
            }
        }
    }
}

export default (client: Client) => ({
    /**
     * API version details, including some parts of the global datacenter config.
     * @endpoint GET /version
     * @allowToken 1
     * @permissions {"user": "all"}
     */
    version: (...args: ArgsTuple<VersionAPI["/version"]["GET"]['parameters']>) => client.request("/version", "GET", (args[0] ?? {}) as VersionAPI["/version"]["GET"]['parameters'])
}) as const

import http from "node:http";
import https from "node:https";
import {PassThrough} from "node:stream";
import {afterEach, describe, expect, it, vi} from "vitest";
import native_fetch from "./fetch";

describe("native_fetch", () => {
    afterEach(() => {
        vi.restoreAllMocks();
    });

    it("sends body buffers and sets content-length automatically", async () => {
        const requestSpy = vi.spyOn(http, "request").mockImplementation((options: any, callback: any) => {
            const req = new PassThrough() as PassThrough & {
                destroy: (error?: Error) => void;
                write: (chunk: Buffer | string) => boolean;
                end: () => void;
            };
            const bodyChunks: Buffer[] = [];
            req.write = (chunk: Buffer | string) => {
                bodyChunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
                return true;
            };
            req.end = () => {
                const res = new PassThrough() as PassThrough & {
                    statusCode: number;
                    statusMessage: string;
                    headers: http.IncomingHttpHeaders;
                };
                res.statusCode = 200;
                res.statusMessage = "OK";
                res.headers = {"content-type": "application/json"};
                callback(res);
                res.end(
                    JSON.stringify({
                        method: options.method,
                        headers: options.headers,
                        body: Buffer.concat(bodyChunks).toString("utf8"),
                    })
                );
                req.emit("close");
            };
            req.destroy = (error?: Error) => {
                if (error) req.emit("error", error);
                req.emit("close");
            };
            return req as never;
        });

        const response = await native_fetch("http://example.test/echo", {
            method: "POST",
            headers: {"x-test": "yes"},
            body: new Uint8Array([65, 66]) as unknown as BodyInit,
        });
        const data = await response.json() as Record<string, any>;

        expect(data.method).toBe("POST");
        expect(data.body).toBe("AB");
        expect(data.headers["x-test"]).toBe("yes");
        expect(data.headers["content-length"]).toBe("2");
        expect(requestSpy).toHaveBeenCalledOnce();
    });

    it("merges Request and init values while preferring init method/body", async () => {
        vi.spyOn(http, "request").mockImplementation((options: any, callback: any) => {
            const req = new PassThrough() as PassThrough & {
                destroy: (error?: Error) => void;
                write: (chunk: Buffer | string) => boolean;
                end: () => void;
            };
            const bodyChunks: Buffer[] = [];
            req.write = (chunk: Buffer | string) => {
                bodyChunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
                return true;
            };
            req.end = () => {
                const res = new PassThrough() as PassThrough & {
                    statusCode: number;
                    statusMessage: string;
                    headers: http.IncomingHttpHeaders;
                };
                res.statusCode = 200;
                res.statusMessage = "OK";
                res.headers = {"content-type": "application/json"};
                callback(res);
                res.end(
                    JSON.stringify({
                        method: options.method,
                        headers: options.headers,
                        body: Buffer.concat(bodyChunks).toString("utf8"),
                        path: options.path,
                    })
                );
                req.emit("close");
            };
            req.destroy = (error?: Error) => {
                if (error) req.emit("error", error);
                req.emit("close");
            };
            return req as never;
        });

        const request = new Request("http://example.test/merged?x=1", {
            method: "POST",
            headers: {"x-from-request": "r1"},
            body: "request-body",
        });

        const response = await native_fetch(request, {
            method: "PUT",
            headers: {"x-from-init": "i1"},
            body: "init-body",
        });
        const data = await response.json() as Record<string, any>;

        expect(data.method).toBe("PUT");
        expect(data.body).toBe("init-body");
        expect(data.path).toBe("/merged?x=1");
        expect(data.headers["x-from-request"]).toBe("r1");
        expect(data.headers["x-from-init"]).toBe("i1");
    });

    it("supports abort signals", async () => {
        vi.spyOn(http, "request").mockImplementation(() => {
            const req = new PassThrough() as PassThrough & {
                destroy: (error?: Error) => void;
                write: (chunk: Buffer | string) => boolean;
                end: () => void;
            };
            req.write = () => true;
            req.end = () => undefined;
            req.destroy = (error?: Error) => {
                if (error) req.emit("error", error);
                req.emit("close");
            };
            return req as never;
        });
        vi.spyOn(https, "request").mockImplementation(http.request as never);

        const controller = new AbortController();
        const promise = native_fetch("http://example.test/slow", {signal: controller.signal});
        controller.abort();

        await expect(promise).rejects.toMatchObject({name: "AbortError"});
    });
});

import http from "node:http";
import https from "node:https";
import {Readable} from "node:stream";
import {Agent as HttpAgent} from "node:http";
import {Agent as HttpsAgent} from "node:https";

type AnyAgent = HttpAgent | HttpsAgent;

type NativeFetchInit = RequestInit & { agent?: AnyAgent };

function isHttps(url: URL) {
    return url.protocol === "https:";
}

function mergeHeaders(base?: HeadersInit, extra?: HeadersInit): Headers {
    const h = new Headers(base);
    if (extra) {
        const e = new Headers(extra);
        e.forEach((v, k) => h.set(k, v));
    }
    return h;
}

async function bodyToBuffer(body: unknown): Promise<Buffer | undefined> {
    if (body == null) return undefined;

    // String
    if (typeof body === "string") return Buffer.from(body);

    // Buffer
    if (Buffer.isBuffer(body)) return body;

    // Uint8Array / ArrayBuffer
    if (body instanceof Uint8Array) return Buffer.from(body);
    if (body instanceof ArrayBuffer) return Buffer.from(new Uint8Array(body));

    // Blob
    if (typeof Blob !== "undefined" && body instanceof Blob) {
        const ab = await body.arrayBuffer();
        return Buffer.from(new Uint8Array(ab));
    }

    // WHATWG ReadableStream -> buffer (basic support)
    if (typeof ReadableStream !== "undefined" && body instanceof ReadableStream) {
        const reader = body.getReader();
        const chunks: Buffer[] = [];
        while (true) {
            const {value, done} = await reader.read();
            if (done) break;
            chunks.push(Buffer.from(value));
        }
        return Buffer.concat(chunks);
    }

    // Node Readable -> buffer (basic support)
    if (body && typeof (body as any).pipe === "function") {
        const chunks: Buffer[] = [];
        for await (const chunk of body as any as AsyncIterable<Buffer | string>) {
            chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
        }
        return Buffer.concat(chunks);
    }

    throw new TypeError(
        `Unsupported body type for native_fetch: ${Object.prototype.toString.call(body)}`
    );
}

const native_fetch: typeof fetch = async (
    input: string | URL | Request,
    init?: NativeFetchInit
): Promise<Response> => {
    // Normalize input into URL + Request fields
    let url: URL;
    let request: Request | undefined;

    if (input instanceof Request) {
        request = input;
        url = new URL(request.url);
    } else if (input instanceof URL) {
        url = input;
    } else {
        url = new URL(input);
    }

    // Merge init with Request (init should override Request)
    const method = (init?.method ?? request?.method ?? "GET").toUpperCase();

    const headers = mergeHeaders(request?.headers, init?.headers);

    // Body precedence:
    // - If init.body present -> use it
    // - else if Request has a body -> use that (buffered)
    const bodySource =
        init && "body" in init && init.body !== undefined ? init.body : request;

    let bodyBuffer: Buffer | undefined;

    if (bodySource instanceof Request) {
        // Only read Request body if method typically allows it
        // (and if body exists)
        if (method !== "GET" && method !== "HEAD") {
            // Cloning avoids "body already used" issues if caller reuses request elsewhere
            const clone = bodySource.clone();
            const ab = await clone.arrayBuffer().catch(() => undefined);
            if (ab) bodyBuffer = Buffer.from(new Uint8Array(ab));
        }
    } else {
        bodyBuffer = await bodyToBuffer(bodySource);
    }

    // Set Content-Length if we have a concrete body and caller didn't set it
    if (
        bodyBuffer &&
        !headers.has("content-length") &&
        method !== "GET" &&
        method !== "HEAD"
    ) {
        headers.set("content-length", String(bodyBuffer.byteLength));
    }

    // Default Host header is handled by node, but keeping user header if provided is fine.
    // Basic request options
    const port =
        url.port !== ""
            ? Number(url.port)
            : isHttps(url)
                ? 443
                : 80;

    const options: http.RequestOptions = {
        protocol: url.protocol,
        hostname: url.hostname,
        port,
        path: url.pathname + url.search,
        method,
        headers: Object.fromEntries(headers.entries()),
        agent: init?.agent,
    };

    const signal = init?.signal ?? request?.signal;

    const transport = isHttps(url) ? https : http;

    return await new Promise<Response>((resolve, reject) => {
        const req = transport.request(options, (res) => {
            // Convert Node headers -> WHATWG Headers
            const resHeaders = new Headers();
            for (const [k, v] of Object.entries(res.headers)) {
                if (typeof v === "undefined") continue;
                if (Array.isArray(v)) {
                    // Multiple headers with same name
                    for (const vv of v) resHeaders.append(k, vv);
                } else {
                    resHeaders.set(k, v);
                }
            }

            const status = res.statusCode ?? 0;
            const statusText = res.statusMessage ?? "";

            // Convert Node Readable -> Web ReadableStream for Response
            const webBody = (Readable as any).toWeb
                ? (Readable as any).toWeb(res)
                : undefined;

            // Note: Response() accepts null body; for HEAD responses body is empty anyway.
            const response = new Response(webBody ?? null, {
                status,
                statusText,
                headers: resHeaders,
            });

            resolve(response);
        });

        req.on("error", reject);

        // Abort handling
        if (signal) {
            if (signal.aborted) {
                req.destroy(new DOMException("Aborted", "AbortError"));
                return reject(new DOMException("Aborted", "AbortError"));
            }
            const onAbort = () => {
                req.destroy(new DOMException("Aborted", "AbortError"));
                reject(new DOMException("Aborted", "AbortError"));
            };
            signal.addEventListener("abort", onAbort, {once: true});
            req.on("close", () => {
                signal.removeEventListener("abort", onAbort);
            });
        }

        // Write body (buffered)
        if (bodyBuffer && method !== "GET" && method !== "HEAD") {
            req.write(bodyBuffer);
        }
        req.end();
    });
};

export default native_fetch

import EventEmitter from "node:events";
import type {Client} from "../index";
import WS, {type RawData} from "ws";

type VMType = "qemu" | "lxc";

export type DisplayTicket = {
    cert: string;
    port: number;
    ticket: string;
    upid: string;
    user: string;
    password?: string;
};

export type DisplayConnectionInfo = {
    vmid: number;
    node: string;
    type: VMType;
    ticket: DisplayTicket;
    websocketUrl: string;
};

export type DisplayPipe = {
    send(data: string | ArrayBufferLike | Blob | ArrayBufferView): void;
    close(code?: number, data?: string | Buffer): void;
    on(event: "message", listener: (data: Buffer | string) => void): unknown;
    once(event: "close", listener: () => void): unknown;
} & EventEmitter;

export type DisplayOpenOptions = {
    rejectUnauthorized?: boolean;
    pipeTo?: DisplayPipe;
};

function rawToBuffer(data: RawData): Buffer {
    if (typeof data === "string") return Buffer.from(data);
    if (Buffer.isBuffer(data)) return data;
    if (data instanceof ArrayBuffer) return Buffer.from(data);
    if (Array.isArray(data)) return Buffer.concat(data.map((part) => Buffer.isBuffer(part) ? part : Buffer.from(part)));
    throw new Error(`Unsupported websocket payload type: ${Object.prototype.toString.call(data)}`);
}

export class DisplaySession extends EventEmitter<{
    ready: [];
    data: [Buffer];
    close: [];
    error: [Error];
}> {
    constructor(private readonly socket: WS) {
        super();
        this.bind();
    }

    private bind() {
        this.socket.on("open", () => {
            this.emit("ready");
        });

        this.socket.on("message", (raw) => {
            this.emit("data", rawToBuffer(raw));
        });

        this.socket.on("close", () => {
            this.emit("close");
        });

        this.socket.on("error", (error) => {
            const err = error instanceof Error ? error : new Error(String(error));
            this.emit("error", err);
        });
    }

    write(data: string | Buffer | Uint8Array): boolean {
        if (this.socket.readyState !== WS.OPEN) return false;
        this.socket.send(data);
        return true;
    }

    close(code?: number, reason?: string | Buffer) {
        if (this.socket.readyState === WS.OPEN || this.socket.readyState === WS.CONNECTING) {
            this.socket.close(code, typeof reason === "string" ? reason : reason?.toString("utf8"));
        }
    }

    pipe<T extends DisplayPipe>(target: T): T {
        this.on("data", (data) => target.send(data));
        target.on("message", (data) => {
            const payload = Buffer.isBuffer(data) ? data : Buffer.from(data);
            this.write(payload);
        });
        target.once("close", () => this.close());
        this.once("close", () => target.close());
        return target;
    }
}

export class Display {
    private cachedTicket?: DisplayTicket;

    constructor(
        private readonly vmid: string | number,
        private readonly client: Client
    ) {
    }

    get ticket(): DisplayTicket | undefined {
        return this.cachedTicket;
    }

    async createTicket(): Promise<DisplayTicket> {
        const vm = await this.getRunningVm();
        const ticket = await this.client.request(
            `/nodes/{node}/${vm.type}/{vmid}/vncproxy`,
            "POST",
            {
                $path: {
                    node: vm.node,
                    vmid: vm.vmid,
                },
                $body: {
                    websocket: true,
                },
            } as any
        );
        this.cachedTicket = ticket as DisplayTicket;
        return this.cachedTicket;
    }

    async getConnectionInfo(): Promise<DisplayConnectionInfo> {
        const vm = await this.getRunningVm();
        const ticket = this.cachedTicket ?? (await this.createTicket());
        const websocketPath = `/nodes/${encodeURIComponent(vm.node)}/${vm.type}/${encodeURIComponent(vm.vmid.toString())}/vncwebsocket`;
        const httpUrl = this.client.url(websocketPath, {
            port: ticket.port,
            vncticket: ticket.ticket,
        });
        const wsUrl = new URL(httpUrl);
        wsUrl.protocol = wsUrl.protocol === "https:" ? "wss:" : "ws:";

        return {
            vmid: vm.vmid,
            node: vm.node,
            type: vm.type,
            ticket,
            websocketUrl: wsUrl.toString(),
        };
    }

    async open(options: DisplayOpenOptions = {}): Promise<DisplaySession> {
        const info = await this.getConnectionInfo();
        const wsUrl = new URL(info.websocketUrl);
        const originProtocol = wsUrl.protocol === "wss:" ? "https:" : "http:";
        const origin = `${originProtocol}//${wsUrl.host}`;

        const headers: Record<string, string> = {
            Origin: origin,
        };

        const cookie = this.client.sessionCookie();
        if (cookie) headers.Cookie = cookie;

        const token = this.client.tokenAuthorizationHeader();
        if (token) headers.Authorization = token;

        if (!headers.Cookie && !headers.Authorization) {
            throw new Error("Missing websocket authentication headers (cookie or API token).");
        }

        const socket = new WS(info.websocketUrl, {
            headers,
            rejectUnauthorized: options.rejectUnauthorized ?? false,
        });

        const session = new DisplaySession(socket);
        if (options.pipeTo) {
            session.pipe(options.pipeTo);
        }
        return session;
    }

    private async getRunningVm(): Promise<{ vmid: number; node: string; type: VMType }> {
        const resources = await this.client.request("/cluster/resources", "GET", {
            $query: {type: "vm"},
        });

        const vm = resources.find((resource) => resource.vmid?.toString() === this.vmid.toString());

        if (!vm) throw new Error(`Unable to find virtual machine with id(${this.vmid}).`);
        if (vm.status !== "running") throw new Error(`Virtual machine ${this.vmid} is not running.`);
        if (!vm.node || !vm.vmid) throw new Error(`Virtual machine ${this.vmid} does not include node/vmid data.`);
        if (vm.type !== "qemu" && vm.type !== "lxc") throw new Error(`Unsupported VM type '${vm.type}' for display helper.`);

        return {
            vmid: vm.vmid,
            node: vm.node,
            type: vm.type,
        };
    }
}

import EventEmitter from "node:events";
import type {ClusterAPI} from "../api/cluster";
import type {Client} from "../index";
import WS, {type RawData} from "ws";

type VMType = "qemu" | "lxc";
type ClusterResource = ClusterAPI["/cluster/resources"]["GET"]["return"][number];

type SocketBuildResult = {
    info: TerminalConnectionInfo;
    socket: WS;
};

type SocketFactory = () => Promise<SocketBuildResult>;

export type TerminalTicket = {
    port: number;
    ticket: string;
    upid: string;
    user: string;
};

export type TerminalConnectionInfo = {
    vmid: number;
    node: string;
    type: VMType;
    ticket: TerminalTicket;
    websocketUrl: string;
    authMessage: string;
};

export enum TerminalState {
    START = 1,
    CONNECTING = 2,
    CONNECTED = 3,
    DISCONNECTING = 4,
    DISCONNECTED = 5,
    RECONNECTING = 6,
}

export type TerminalPipe = {
    send(data: string | ArrayBufferLike | Blob | ArrayBufferView): void;
    close(code?: number, data?: string | Buffer): void;
    on(event: "message", listener: (data: Buffer | string) => void): unknown;
    once(event: "close", listener: () => void): unknown;
} & EventEmitter;

export type TerminalOpenOptions = {
    rejectUnauthorized?: boolean;
    pipeTo?: TerminalPipe;
    reconnect?: boolean;
    reconnectIntervalMs?: number;
    reconnectMaxAttempts?: number;
};

function rawToBuffer(data: RawData): Buffer {
    if (typeof data === "string") return Buffer.from(data);
    if (Buffer.isBuffer(data)) return data;
    if (data instanceof ArrayBuffer) return Buffer.from(data);
    if (Array.isArray(data)) return Buffer.concat(data.map((part) => Buffer.isBuffer(part) ? part : Buffer.from(part)));
    throw new Error(`Unsupported websocket payload type: ${Object.prototype.toString.call(data)}`);
}

export class TerminalSession extends EventEmitter<{
    ready: [];
    data: [Buffer];
    close: [];
    resize: [number, number];
    error: [Error];
    state: [TerminalState, TerminalState];
    reconnect: [number];
}> {
    private socket?: WS;
    private stateValue: TerminalState = TerminalState.START;
    private keepAlive?: NodeJS.Timeout;
    private reconnectTimer?: NodeJS.Timeout;
    private manuallyClosed = false;
    private reconnectAttempts = 0;
    private info?: TerminalConnectionInfo;

    constructor(
        private readonly createSocket: SocketFactory,
        private readonly options: Required<Pick<TerminalOpenOptions, "reconnect" | "reconnectIntervalMs" | "reconnectMaxAttempts">>
    ) {
        super();
        this.bindResizeHandler();
    }

    get state() {
        return this.stateValue;
    }

    get connectionInfo() {
        return this.info;
    }

    async start() {
        await this.connect();
    }

    private bindResizeHandler() {
        this.on("resize", (columns, rows) => {
            if (this.state !== TerminalState.CONNECTED || !this.socket || this.socket.readyState !== WS.OPEN) return;
            this.socket.send(`1:${columns}:${rows}:`);
        });
    }

    private setState(next: TerminalState) {
        const prev = this.stateValue;
        this.stateValue = next;
        this.emit("state", next, prev);
    }

    private clearTimers() {
        if (this.keepAlive) {
            clearInterval(this.keepAlive);
            this.keepAlive = undefined;
        }
        if (this.reconnectTimer) {
            clearTimeout(this.reconnectTimer);
            this.reconnectTimer = undefined;
        }
    }

    private async connect() {
        try {
            const {socket, info} = await this.createSocket();
            this.socket = socket;
            this.info = info;
            this.bindSocket(socket, info);
        } catch (error) {
            const err = error instanceof Error ? error : new Error(String(error));
            this.emit("error", err);
            this.scheduleReconnect();
        }
    }

    private bindSocket(socket: WS, info: TerminalConnectionInfo) {
        socket.on("open", () => {
            this.setState(TerminalState.CONNECTING);
            socket.send(info.authMessage);

            this.keepAlive = setInterval(() => {
                if (socket.readyState === WS.OPEN) {
                    socket.send("2");
                }
            }, 30_000);
        });

        socket.on("message", (raw) => {
            const data = rawToBuffer(raw);

            if (this.state === TerminalState.CONNECTING) {
                if (data.length >= 2 && data[0] === 79 && data[1] === 75) {
                    this.reconnectAttempts = 0;
                    this.setState(TerminalState.CONNECTED);
                    this.emit("ready");
                    const rest = data.subarray(2);
                    if (rest.length) this.emit("data", rest);
                } else {
                    socket.close();
                }
                return;
            }

            if (this.state === TerminalState.CONNECTED) {
                this.emit("data", data);
            }
        });

        socket.on("close", () => {
            this.clearTimers();
            this.emit("close");

            if (this.manuallyClosed) {
                this.setState(TerminalState.DISCONNECTED);
                return;
            }
            this.scheduleReconnect();
        });

        socket.on("error", (error) => {
            const err = error instanceof Error ? error : new Error(String(error));
            this.emit("error", err);
        });
    }

    private scheduleReconnect() {
        if (!this.options.reconnect) {
            this.setState(TerminalState.DISCONNECTED);
            return;
        }

        if (this.reconnectAttempts >= this.options.reconnectMaxAttempts) {
            this.setState(TerminalState.DISCONNECTED);
            return;
        }

        this.reconnectAttempts += 1;
        this.setState(TerminalState.RECONNECTING);
        this.emit("reconnect", this.reconnectAttempts);

        this.reconnectTimer = setTimeout(() => {
            void this.connect();
        }, this.options.reconnectIntervalMs);
    }

    write(data: string): boolean {
        if (this.state !== TerminalState.CONNECTED || !this.socket || this.socket.readyState !== WS.OPEN) {
            return false;
        }
        this.socket.send(`0:${Buffer.byteLength(data, "utf8")}:${data}`);
        return true;
    }

    close(code?: number, reason?: string | Buffer) {
        this.manuallyClosed = true;
        this.setState(TerminalState.DISCONNECTING);
        this.clearTimers();
        if (this.socket && (this.socket.readyState === WS.OPEN || this.socket.readyState === WS.CONNECTING)) {
            this.socket.close(code, typeof reason === "string" ? reason : reason?.toString("utf8"));
        } else {
            this.setState(TerminalState.DISCONNECTED);
        }
    }

    pipe<T extends TerminalPipe>(target: T): T {
        this.on("data", (data) => target.send(data));
        target.on("message", (data) => {
            const text = Buffer.isBuffer(data) ? data.toString("utf8") : data;
            this.write(text);
        });
        target.once("close", () => this.close());
        this.once("close", () => target.close());
        return target;
    }
}

export class Terminal {
    private cachedTicket?: TerminalTicket;

    constructor(
        private readonly vmid: string | number,
        private readonly client: Client
    ) {
    }

    get ticket() {
        return this.cachedTicket;
    }

    async createTicket(): Promise<TerminalTicket> {
        const vm = await this.getRunningVm();
        const ticket = await this.client.request(
            `/nodes/{node}/${vm.type}/{vmid}/termproxy`,
            "POST",
            {
                $path: {
                    node: vm.node,
                    vmid: vm.vmid,
                },
            } as any
        );
        this.cachedTicket = ticket as TerminalTicket;
        return this.cachedTicket;
    }

    async getConnectionInfo(): Promise<TerminalConnectionInfo> {
        const vm = await this.getRunningVm();
        const ticket = this.cachedTicket ?? (await this.createTicket());
        const websocketPath = `/nodes/${encodeURIComponent(vm.node)}/${vm.type}/${encodeURIComponent(vm.vmid.toString())}/vncwebsocket`;
        const httpUrl = this.client.url(websocketPath, {
            port: ticket.port,
            vncticket: ticket.ticket,
        });
        const wsUrl = new URL(httpUrl);
        wsUrl.protocol = wsUrl.protocol === "https:" ? "wss:" : "ws:";

        return {
            vmid: vm.vmid,
            node: vm.node,
            type: vm.type,
            ticket,
            websocketUrl: wsUrl.toString(),
            authMessage: `${ticket.user}:${ticket.ticket}\n`,
        };
    }

    async open(options: TerminalOpenOptions = {}): Promise<TerminalSession> {
        const session = new TerminalSession(
            async () => {
                const info = await this.getConnectionInfo();
                const cookie = this.client.sessionCookie();
                if (!cookie) {
                    throw new Error("Missing authenticated session cookie. Did you call login()?");
                }

                const wsUrl = new URL(info.websocketUrl);
                const originProtocol = wsUrl.protocol === "wss:" ? "https:" : "http:";
                const origin = `${originProtocol}//${wsUrl.host}`;

                const socket = new WS(info.websocketUrl, {
                    headers: {
                        Cookie: cookie,
                        Origin: origin,
                    },
                    rejectUnauthorized: options.rejectUnauthorized ?? false,
                });

                return {info, socket};
            },
            {
                reconnect: options.reconnect ?? true,
                reconnectIntervalMs: Math.max(250, options.reconnectIntervalMs ?? 1500),
                reconnectMaxAttempts: options.reconnectMaxAttempts ?? Number.POSITIVE_INFINITY,
            }
        );

        if (options.pipeTo) {
            session.pipe(options.pipeTo);
        }

        await session.start();
        return session;
    }

    private async getRunningVm(): Promise<{ vmid: number; node: string; type: VMType }> {
        const resources = await this.client.request("/cluster/resources", "GET", {
            $query: {type: "vm"},
        } as any);

        const vm = (resources as ClusterResource[]).find(
            (resource) => resource.vmid?.toString() === this.vmid.toString()
        );

        if (!vm) {
            throw new Error(`Unable to find virtual machine with id(${this.vmid}).`);
        }
        if (vm.status !== "running") {
            throw new Error(`Virtual machine ${this.vmid} is not running.`);
        }
        if (!vm.node || !vm.vmid) {
            throw new Error(`Virtual machine ${this.vmid} does not include node/vmid data.`);
        }
        if (vm.type !== "qemu" && vm.type !== "lxc") {
            throw new Error(`Unsupported VM type '${vm.type}' for terminal helper.`);
        }

        return {
            vmid: vm.vmid,
            node: vm.node,
            type: vm.type,
        };
    }
}

import {describe, expect, it, vi} from "vitest";
import {EventFilter, TimerPulledEventEmitter} from "./TimerPulledEventEmitter";

type Events = {
    alpha: {count: number};
    beta: string;
};

describe("TimerPulledEventEmitter", () => {
    it("publishes only changed values and tracks history", async () => {
        let value = 1;
        const emitter = new TimerPulledEventEmitter<Events>(({publish}) => {
            publish("alpha", {count: value});
        }, 5_000);
        emitter.stop();

        const seen: Array<{count: number}> = [];
        emitter.on("alpha", (event) => seen.push(event));

        await emitter.pullNow();
        await emitter.pullNow();
        value = 2;
        await emitter.pullNow();

        expect(seen).toEqual([{count: 1}, {count: 2}]);
        expect(emitter.history).toEqual([{count: 2}]);
    });

    it("supports filters and filter removal", async () => {
        const emitter = new TimerPulledEventEmitter<Events>(({publish}) => {
            publish("beta", "match");
            publish("alpha", {count: 10});
        }, 5_000);
        emitter.stop();

        const listener = vi.fn();
        const predicate = vi.fn((value: Events[keyof Events], key: keyof Events) => key === "beta" && value === "match");
        const filter = emitter.filter(predicate as never, listener as never);

        await emitter.pullNow();
        expect(predicate).toHaveBeenCalled();
        expect(listener).toHaveBeenCalledWith("match", "beta");

        const removed = emitter.removeFilter(filter);
        expect(removed).toBe(true);

        listener.mockClear();
        await emitter.pullNow();
        expect(listener).not.toHaveBeenCalled();
    });

    it("emits errors to listeners, or console when no listener exists", async () => {
        const expected = new Error("boom");
        const emitter = new TimerPulledEventEmitter<Events>(async () => {
            throw expected;
        }, 5_000);
        emitter.stop();

        const onError = vi.fn();
        emitter.on("error", onError);
        await emitter.pullNow();
        expect(onError).toHaveBeenCalledWith(expected);

        emitter.off("error", onError);
        const consoleSpy = vi.spyOn(console, "error").mockImplementation(() => undefined);
        await emitter.pullNow();
        expect(consoleSpy).toHaveBeenCalled();

        consoleSpy.mockRestore();
    });

    it("matches EventFilter instances and callback pairs", () => {
        const predicate = vi.fn(() => true);
        const listener = vi.fn();
        const filter = new EventFilter(predicate as never, listener as never);

        expect(filter.matches(filter)).toBe(true);
        expect(filter.matches(predicate as never, listener as never)).toBe(true);
        expect(filter.matches(vi.fn(() => true) as never, listener as never)).toBe(false);
    });
});

import {EventEmitter} from "node:events";

type EventKey = string | symbol;
type EventValueMap = object;
type ManagedEventKey<T extends EventValueMap> = Extract<keyof T, EventKey>;
type NodeEventMap<T extends EventValueMap> = {
    [K in ManagedEventKey<T>]: [T[K]];
};

export type PullContext<T extends EventValueMap> = {
    readonly emittedEvents: Map<ManagedEventKey<T>, T[ManagedEventKey<T>]>;
    publish<K extends ManagedEventKey<T>>(key: K, value: T[K]): boolean;
};

export type PullFunction<T extends EventValueMap> = (
    context: PullContext<T>
) => Promise<void> | void;

export type EventFilterPredicate<T extends EventValueMap> = (
    value: T[ManagedEventKey<T>],
    key: ManagedEventKey<T>
) => boolean;
export type EventFilterListener<T extends EventValueMap> = (
    value: T[ManagedEventKey<T>],
    key: ManagedEventKey<T>
) => void;

export class EventFilter<T extends EventValueMap> {
    constructor(
        private readonly predicate: EventFilterPredicate<T>,
        private readonly listener: EventFilterListener<T>
    ) {
    }

    test(value: T[ManagedEventKey<T>], key: ManagedEventKey<T>): boolean {
        if (!this.predicate(value, key)) return false;
        this.listener(value, key);
        return true;
    }

    matches(filter: EventFilter<T>): boolean;
    matches(predicate: EventFilterPredicate<T>, listener: EventFilterListener<T>): boolean;
    matches(predicate: EventFilterPredicate<T> | EventFilter<T>, listener?: EventFilterListener<T>): boolean {
        if (predicate instanceof EventFilter) {
            return predicate === this || (predicate.predicate === this.predicate && predicate.listener === this.listener);
        }
        return this.predicate === predicate && this.listener === listener;
    }
}

export class TimerPulledEventEmitter<T extends EventValueMap> extends EventEmitter<NodeEventMap<T>> {
    private timer?: NodeJS.Timeout;
    private filters: EventFilter<T>[] = [];
    private emittedEvents = new Map<ManagedEventKey<T>, T[ManagedEventKey<T>]>();
    private running = false;

    constructor(
        private readonly pullFn: PullFunction<T>,
        private pollInterval = 3000
    ) {
        super();
        this.start();
    }

    get interval(): number {
        return this.pollInterval;
    }

    set interval(value: number) {
        this.pollInterval = Math.max(100, value);
        if (!this.running) return;
        this.stop();
        this.start();
    }

    get history(): Array<T[ManagedEventKey<T>]> {
        return Array.from(this.emittedEvents.values());
    }

    start() {
        if (this.running) return;
        this.running = true;
        this.timer = setInterval(() => {
            void this.pullNow();
        }, this.pollInterval);
    }

    stop() {
        if (!this.running) return;
        this.running = false;
        if (this.timer) clearInterval(this.timer);
        this.timer = undefined;
    }

    destroy() {
        this.stop();
        this.removeAllListeners();
        this.filters = [];
        this.emittedEvents.clear();
    }

    clearCache() {
        this.emittedEvents.clear();
    }

    on<K extends ManagedEventKey<T>>(eventName: K, listener: (value: T[K]) => void): this;
    on(eventName: "error", listener: (error: Error) => void): this;
    on(eventName: EventKey, listener: (...args: any[]) => void): this {
        super.on(eventName, listener);
        return this;
    }

    once<K extends ManagedEventKey<T>>(eventName: K, listener: (value: T[K]) => void): this;
    once(eventName: "error", listener: (error: Error) => void): this;
    once(eventName: EventKey, listener: (...args: any[]) => void): this {
        super.once(eventName, listener);
        return this;
    }

    off<K extends ManagedEventKey<T>>(eventName: K, listener: (value: T[K]) => void): this;
    off(eventName: "error", listener: (error: Error) => void): this;
    off(eventName: EventKey, listener: (...args: any[]) => void): this {
        super.off(eventName, listener);
        return this;
    }

    async pullNow() {
        try {
            await this.pullFn({
                publish: this.publish.bind(this),
                emittedEvents: this.emittedEvents
            });
        } catch (error) {
            // Keep polling alive while surfacing failures to consumers.
            if (this.listenerCount("error") > 0) {
                (super.emit as (eventName: EventKey, ...args: unknown[]) => boolean)("error", error as Error);
            } else {
                console.error(error);
            }
        }
    }

    private publish<K extends ManagedEventKey<T>>(key: K, value: T[K]): boolean {
        const previous = this.emittedEvents.get(key);
        if (previous !== undefined && this.deepEqual(previous, value)) {
            return false;
        }
        this.emittedEvents.set(key, value);
        const emitted = (super.emit as (eventName: EventKey, ...args: unknown[]) => boolean)(
            key as EventKey,
            value
        );
        const typedKey = key as ManagedEventKey<T>;
        for (const filter of this.filters) {
            filter.test(value as T[ManagedEventKey<T>], typedKey);
        }
        return emitted;
    }

    filter(filter: EventFilter<T>): EventFilter<T>;
    filter(predicate: EventFilterPredicate<T>, listener: EventFilterListener<T>): EventFilter<T>;
    filter(predicate: EventFilterPredicate<T> | EventFilter<T>, listener?: EventFilterListener<T>): EventFilter<T> {
        if (predicate instanceof EventFilter) {
            this.filters.push(predicate);
            return predicate;
        }
        const eventFilter = new EventFilter(predicate, listener as EventFilterListener<T>);
        this.filters.push(eventFilter);
        return eventFilter;
    }

    removeFilter(filter: EventFilter<T>): boolean;
    removeFilter(predicate: EventFilterPredicate<T>, listener: EventFilterListener<T>): boolean;
    removeFilter(predicate: EventFilterPredicate<T> | EventFilter<T>, listener?: EventFilterListener<T>): boolean {
        const before = this.filters.length;
        this.filters = this.filters.filter((f) => !f.matches(predicate as never, listener as never));
        return before !== this.filters.length;
    }

    private deepEqual(a: unknown, b: unknown): boolean {
        if (a === b) return true;
        if (typeof a !== "object" || typeof b !== "object" || !a || !b) return false;
        const aObj = a as Record<string, unknown>;
        const bObj = b as Record<string, unknown>;
        const aKeys = Object.keys(aObj);
        const bKeys = Object.keys(bObj);
        if (aKeys.length !== bKeys.length) return false;
        for (const key of aKeys) {
            if (!(key in bObj)) return false;
            if (!this.deepEqual(aObj[key], bObj[key])) return false;
        }
        return true;
    }
}

import {afterEach, beforeEach, describe, expect, it, vi} from "vitest";
